export async function getDirectorPersonaId(): Promise<string> {
  return invoke<string>('get_director_persona_id');
}

/** Portfolio analytics for the command center (fleet rollup + in-scope roster + score distribution). */
export async function getDirectorPortfolio(days?: number): Promise<DirectorPortfolio> {
  return invoke<DirectorPortfolio>('get_director_portfolio', { days: days ?? null });
}

// A single Director target runs TWO sequential LLM executions through the
// execution runner — the evaluation (polled up to 360s) AND the per-persona
// memory-cleanup pass (another up to 360s) — plus queue/finalize latency, so the
// real worst case is ~2×360s + overhead. The old 420s ceiling rejected mid-run
// while the backend kept evaluating and writing verdicts; a user retry then
// spawned a duplicate concurrent cycle (doubled verdicts + LLM spend). Size for
// the double run.
const DIRECTOR_RUN_TIMEOUT_MS = 900_000; // 15 min — one target (eval + cleanup)
// The batch runs that same single-target cycle sequentially per starred persona,
// so its budget must scale with the count instead of a fixed 30 min (which N≥3
// slow personas blew, causing the same premature-reject → duplicate-run problem).
const DIRECTOR_PER_PERSONA_TIMEOUT_MS = DIRECTOR_RUN_TIMEOUT_MS;
const DIRECTOR_BATCH_MIN_TIMEOUT_MS = 1_800_000; // 30 min floor
// When maxPersonas is null the backend evaluates every starred persona, so we
// can't know N up front; assume a generous upper bound rather than reject a
// legitimate long run (the batch is rate-limited by nature on the backend).
const DIRECTOR_BATCH_ASSUMED_MAX = 20;

function directorBatchTimeoutMs(maxPersonas?: number): number {
  const n = maxPersonas ?? DIRECTOR_BATCH_ASSUMED_MAX;
  return Math.max(DIRECTOR_BATCH_MIN_TIMEOUT_MS, n * DIRECTOR_PER_PERSONA_TIMEOUT_MS);
}

export async function runDirectorOnPersona(personaId: string): Promise<number> {
  return invoke<number>('run_director_on_persona', { personaId }, { timeoutMs: DIRECTOR_RUN_TIMEOUT_MS });
}

/** Outcome of a Director memory-cleanup pass (mirrors engine/director_memory.rs). */
export interface MemoryCleanupReport {
  scanned: number;
  deduped: number;
  llmArchived: number;
  archivedIds: string[];
  dryRun: boolean;
}

/**
 * Curate one persona's memories — dedup sweep + bounded LLM "won't-use" pass.
 * Archives reversibly (tier='archive'); never deletes, never touches core.
 * Long-running (a real Director run); reuses the single-target timeout.
 */
export async function runDirectorMemoryCleanup(
  personaId: string,
  dryRun = false,
): Promise<MemoryCleanupReport> {
  return invoke<MemoryCleanupReport>(
    'run_director_memory_cleanup',
    { personaId, dryRun },
    { timeoutMs: DIRECTOR_RUN_TIMEOUT_MS },
  );
}

// `run_director_batch` has no server-side dedup, and its 30-min timeout
// (unlike single-target `runDirectorOnPersona`, bounded by the 360s backend
// ceiling) can genuinely be exceeded by a large fleet — so a post-timeout
// retry is a real risk of double-charging LLM spend, not just a double-click.
// The idempotencyKey below dedups the common case (overlapping concurrent
// calls, e.g. an impatient double-click on "Run batch" while the first is
// still in flight): they share the same in-flight promise instead of
// spawning a second batch. It does NOT protect a retry issued *after* the
// original settles/times out — that needs backend-side dedup, tracked
// separately.
const RUN_DIRECTOR_BATCH_IDEMPOTENCY_KEY = 'run_director_batch';

export async function runDirectorBatch(maxPersonas?: number): Promise<DirectorReport> {
  return invoke<DirectorReport>(
    'run_director_batch',
    { maxPersonas: maxPersonas ?? null },
    {
      timeoutMs: directorBatchTimeoutMs(maxPersonas),
      idempotencyKey: RUN_DIRECTOR_BATCH_IDEMPOTENCY_KEY,
    },
  );
}

export async function listDirectorVerdicts(personaId?: string): Promise<DirectorVerdictRow[]> {
  return invoke<DirectorVerdictRow[]>('list_director_verdicts', {
    personaId: personaId ?? null,
  });
}

/**
 * Recent Director scores per persona, oldest→newest. Personas with no scored
 * executions return `[]`. Powers the verdict-trend sparkline on the personas
 * table — one batched call covers every visible row.
 */
export async function listDirectorScoreTrends(
  personaIds: string[],
  limit?: number,
): Promise<Record<string, number[]>> {
  if (personaIds.length === 0) return {};
  return invoke<Record<string, number[]>>('list_director_score_trends', {
    personaIds,
    limit: limit ?? null,
  });
}

/** Whether the Director uses the Obsidian Brain vault as long-term memory. */
export async function getDirectorBrainEnabled(): Promise<boolean> {
  return invoke<boolean>('get_director_brain_enabled');
}

/**
 * The persona's most recent Director coaching notes from the Obsidian Brain
 * vault (markdown, newest-first), or null when Brain is off / no vault / no
 * notes yet. Read-only; powers the prior-coaching panel in the detail modal.
 */
export async function getDirectorBrainHistory(personaId: string): Promise<string | null> {
  return invoke<string | null>('get_director_brain_history', { personaId });
}

/** Toggle the Director's Brain long-term memory (gated on a configured vault). */
export async function setDirectorBrainEnabled(enabled: boolean): Promise<void> {
  return invoke<void>('set_director_brain_enabled', { enabled });
}
